#import <Foundation/Foundation.h>
#import "PLDataProxyProtocol.h"
#import "PLPollingProxyProtocol.h"

//⚠️⚠️⚠️对PollingSDK接口的调用必现经过XPPollingSDK，不接受主工程直接引用PL开头的文件，避免后续维护麻烦

@interface XPPollingSDK : NSObject

+ (void)setupWithLaunchOptions:(NSDictionary *)launchOptions;

+ (void)setKeySettingDataProxy:(id <PLDataProxyProtocol>)keySettingData;

+ (void)setPollingProxy:(id <PLPollingProxyProtocol>)pollingProxy;

+ (void)configPollingMode:(NSInteger)pollingMode;

+ (void)configUnlockLogin:(BOOL)unlockLogin;

+ (void)configWelcomeMode:(BOOL)isWelcomeMode;

+ (void)configUnlockDistance:(float)unlockDistance;

+ (void)configEnableUnlockDistance:(float)enableUnlockDistance;

+ (void)configLockDistance:(float)lockDistance;

+ (void)configStartDistance:(float)startDistance;

+ (void)configLockHoldOnSecond:(float)lockHoldOnSecond;

+ (void)configLockWithSound:(BOOL)isOn;

+ (void)configTxPowerArrayV2:(NSArray<NSDictionary *> *)txPowerArray;

+ (void)configBleAutoSensitivity:(BOOL)bleAutoSensitivity;


@end

